function getRisk(wc, ws, vs) {
  let base = WC_MAP[wc]?.risk || "low";
  if (ws >= 45) return "critical";
  if (vs < 500) return "critical";
  if (vs < 1000 && base === "low") return "medium";
  if (ws >= 30 && base === "low") return "medium";
  if (ws >= 38) return "high";
  return base;
}

